package com.xda.sa2ration.manufacturer;import java.util.Arrays;import java.util.Collections;import java.util.List;public final class ManufacturerBackendRegistry {private ManufacturerBackendRegistry(){}public static List<ManufacturerBackend> all(){return Collections.unmodifiableList(Arrays.asList(new SamsungBackend(),new QualcommBackend(),new MediaTekBackend(),new ExynosBackend(),new XiaomiBackend(),new OnePlusBackend(),new OppoBackend(),new RealmeBackend(),new MotorolaBackend(),new PixelBackend(),new GenericAospBackend()));}public static ManufacturerBackend detect(String signals){for(ManufacturerBackend b:all())if(!(b instanceof GenericAospBackend)&&b.matches(signals))return b;return new GenericAospBackend();}}
